Based on the reference materials and detailed specifications, here's the complete implementation for the required functions:

```cpp
// add+modify_eas_records.hpp
#pragma once

#include <filesystem>
#include <map>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <vector>

#include "eas_common.hpp"
using namespace sqlgen;
using namespace sqlgen::literals;

template<typename T>
void add_eas_records(const std::string& table_name,
                     const std::vector<T>& records) {
  // Connect to the database
  auto conn_result = sqlgen::sqlite::connect(db_path);
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto conn = conn_result.value();

  // Use sqlgen's insert function to add records
  auto insert_result = sqlgen::insert(conn, records);
  if (!insert_result) {
    throw std::runtime_error("Failed to insert records");
  }
}

void delete_eas_records_by_id(const std::string& table_name,
                               const std::string& record_id) {
  // Connect to the database
  auto conn_result = sqlgen::sqlite::connect(db_path);
  if (!conn_result) {
    throw std::runtime_error("Failed to connect to database");
  }
  auto conn = conn_result.value();

  // Determine the primary key column based on table type
  std::string primary_key;
  if (table_name == "Student") {
    primary_key = "SNo";
  } else if (table_name == "Course") {
    primary_key = "CID";
  } else if (table_name == "Score") {
    primary_key = "ScID";
  } else if (table_name == "Major") {
    primary_key = "MID";
  } else {
    throw std::invalid_argument("Invalid table name");
  }

  // Construct the delete statement using sqlgen's delete_from
  auto delete_stmt = sqlgen::delete_from<sqlgen::transpilation::get_table_or_view<T>>() 
                   | sqlgen::where(primary_key == record_id);

  // Execute the delete operation
  auto delete_result = delete_stmt(conn);
  if (!delete_result) {
    throw std::runtime_error("Failed to delete record");
  }
}
```

